var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"너에게는 네가 다해야 할, 그리고 나에게는 내가 다해야 할 의무가 있다.","JPN":"貴様には貴様なりの、そして私には私なりの果たすべき義務がある。","ENG":"We both have our duties which we must exert all of our efforts.","TWN":"你和我都各自有須盡的義務。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그건 노예부터 황제에 이르기까지, 모두에게 해당되는 원칙이지.","JPN":"それは奴隷から皇帝にいたるまで、すべてに当てはまる原則だ。","ENG":"That principle applies to all, whether it be the slave or the emperor.","TWN":"無論是下至奴隸，上至皇太子，人人皆是如此。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러니 너와 나는 대척점에 서 있다, 현자.","JPN":"ゆえに貴様と私は対蹠点に立っていると言える、賢者。","ENG":"As a result, Sage, you and I are at antipodes.","TWN":"因此賢者，你和我是對立的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"둘 중 어느 한 쪽이 자신의 의무를 외면하지 않는 한, 언젠가는 충돌하고 말겠지.","JPN":"どちらかが自分の義務を諦めない限り、いつかは衝突するだろう。","ENG":"Should we both continue to perform our duties unwaveringly, we will clash with each other one day.","TWN":"既然你我二人都無法逃避該盡的義務，那麼總有一天勢必會發生衝突。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"무릇 현자의 계획에는 역경을 딛고 일어설 자들이 필요한 법.","JPN":"たいてい賢者の計画には逆境を乗り超え、立ち上がる者が必要だ。","ENG":"Any plans of yours will require those who will overcome adversity and rise.","TWN":"你的計劃需要能勝過逆境站立起來的人，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"나는 그들이 넘어서야 할 역경이다. 그들에게 처음이자 마지막으로 좌절을 안겨 줄.","JPN":"私は彼らが乗り越えるべき逆境だ。彼らに最初で最後の挫折感を抱かせるための。","ENG":"I am the adversity that they must overcome. I will be the first and last to bestow despair on them.","TWN":"而我就是他們需要跨越的逆境，我會讓他們嚐到第一次，也是最後一次挫折的滋味。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……흠. 눈빛이 한결 진지해졌군. 좋은 표정이다.","JPN":"……ふむ。目がいっそう真剣になったな。いい顔だ。","ENG":"...Hmm. Your eyes have become much more sincere. It is a good expression for you.","TWN":"……哼，眼神有變得認真一點呢，很棒的表情。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"언제까지라도 기다려 주지. 그러니 할 수 있다면 나를 넘어서 봐라.","JPN":"いつまでも待ってやろう。だから、できるものなら私を乗り越えてみせろ。","ENG":"I will wait as long as it takes. Therefore, overcome me if you can.","TWN":"我會一直等著，有辦法的話就儘管跨越我吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러하지 않으면 네가 추구하는 모든 것은, 손에 넣지 못할 허상과 같을 테니.","JPN":"でないと貴様が求めるすべては、手に入れられない虚像と同じになるだろう。","ENG":"If you cannot, then everything you aim for will become dreams that you’ll never accomplish.","TWN":"否則你所追求的一切，就只是想抓也抓不住的浮雲。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};